import React, { useState, useEffect, useRef } from 'react';
import './ChatbotV2.css';
import './ResultsTable.css';
import './Timestamp.css';
import './DataTable.css';
import MarkdownRenderer from './MarkdownRenderer';
import DataInsightsPieChart from './DataInsightsPieChart';

const ChatbotV2 = () => {

  /* -------------------- HELPERS -------------------- */

  const shouldShowPieChart = (data) => {
    if (!Array.isArray(data) || data.length === 0) return false;

    const sample = data[0];
    const hasString = Object.values(sample).some(v => typeof v === 'string');
    const hasNumber = Object.values(sample).some(v => typeof v === 'number');

    return hasString && hasNumber;
  };

  /* -------------------- STATE -------------------- */

  const [messages, setMessages] = useState([
    {
      text: "Hello! I'm your AI Data Assistant. I can help you analyze and retrieve insights from your data. Ask me anything!",
      sender: "bot",
      type: "text",
      timestamp: new Date()
    }
  ]);

  const [customQuery, setCustomQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [expandedMessages, setExpandedMessages] = useState(new Set());
  const [showTechnicalInsights, setShowTechnicalInsights] = useState(false);
  const [latestTechnicalData, setLatestTechnicalData] = useState(null);
  const [activeTab, setActiveTab] = useState('sql');
  const [copySuccess, setCopySuccess] = useState(false);

  const messagesContainerRef = useRef(null);

  /* -------------------- SCROLL -------------------- */

  const scrollToBottom = (smooth = false) => {
    messagesContainerRef.current?.scrollTo({
      top: messagesContainerRef.current.scrollHeight,
      behavior: smooth ? 'smooth' : 'auto'
    });
  };

  /* -------------------- STREAMING -------------------- */

  const handleStreamingResponse = async (query) => {
    setIsProcessing(true);

    const API_BASE_URL =
      process.env.REACT_APP_API_URL || 'http://localhost:3002/api/v1';

    const response = await fetch(`${API_BASE_URL}/chat/ask/stream`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message: query })
    });

    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buffer = '';
    let streamedText = '';
    let initialData = null;

    setMessages(prev => [
      ...prev,
      { text: 'Thinking...', sender: 'bot', type: 'thinking', timestamp: new Date() }
    ]);

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value);
      const lines = buffer.split('\n');
      buffer = lines.pop();

      for (const line of lines) {
        if (!line.startsWith('data: ')) continue;

        const payload = line.replace('data: ', '').trim();
        if (payload === '[DONE]') break;

        const data = JSON.parse(payload);

        /* ---- START ---- */
        if (data.type === 'start') {
          initialData = {
            sql: data.cortexData?.sql || null,
            results:
              data.cortexData?.results ||
              data.cortexData?.rows ||
              data.cortexData?.data ||
              null
          };
        }

        /* ---- CHUNK ---- */
        if (data.type === 'chunk') {
          streamedText += data.content || '';

          setMessages(prev => {
            const copy = [...prev];
            copy[copy.length - 1] = {
              text: streamedText,
              sender: 'bot',
              type: 'markdown',
              timestamp: new Date()
            };
            return copy;
          });

          scrollToBottom(true);
        }

        /* ---- COMPLETE ---- */
        if (data.type === 'complete') {
          setMessages(prev => {
            const copy = [...prev];
            const last = copy[copy.length - 1];

            last.technicalData = {
              sql: initialData?.sql || null,
              dataInsights: initialData?.results || null,
              rowCount: initialData?.results?.length || 0
            };

            console.log(
              '📊 Data Insights:',
              last.technicalData.dataInsights
            );

            setLatestTechnicalData(last.technicalData);
            return copy;
          });

          setIsProcessing(false);
          scrollToBottom(true);
        }
      }
    }
  };

  /* -------------------- UI ACTIONS -------------------- */

  const handleSend = () => {
    if (!customQuery.trim() || isProcessing) return;

    const q = customQuery;
    setCustomQuery('');

    setMessages(prev => [
      ...prev,
      { text: q, sender: 'user', type: 'text', timestamp: new Date() }
    ]);

    handleStreamingResponse(q);
  };

  const toggleMessageExpansion = (index) => {
    setExpandedMessages(prev => {
      const copy = new Set(prev);
      copy.has(index) ? copy.delete(index) : copy.add(index);
      return copy;
    });
  };

  /* -------------------- RENDER -------------------- */

  return (
    <div className="chatbot-v2-container">

      <div className="chatbot-v2-header">
        <h2>Viola Communications</h2>
        <button onClick={() => window.location.reload()}>
          <i className="fas fa-redo" />
        </button>
      </div>

      <div className="chatbot-v2-content">

        <div className="messages-container" ref={messagesContainerRef}>
          {messages.map((msg, index) => (
            <div key={index} className={`message-v2 ${msg.sender}`}>
              <div className="message-bubble">

                {msg.type === 'thinking' && <span>{msg.text}</span>}

                {msg.type === 'markdown' && (
                  <>
                    <MarkdownRenderer content={msg.text} />

                    {msg.technicalData?.dataInsights &&
                      shouldShowPieChart(msg.technicalData.dataInsights) && (
                        <DataInsightsPieChart
                          data={msg.technicalData.dataInsights}
                        />
                      )}
                  </>
                )}

                {msg.type === 'text' && <span>{msg.text}</span>}

                {msg.technicalData && (
                  <button
                    className="tech-insights-inline-btn"
                    onClick={() => {
                      setLatestTechnicalData(msg.technicalData);
                      setShowTechnicalInsights(true);
                    }}
                  >
                    Technical Insights
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>

        <div className="input-area">
          <textarea
            value={customQuery}
            onChange={e => setCustomQuery(e.target.value)}
            placeholder="Ask a question..."
            disabled={isProcessing}
          />
          <button onClick={handleSend} disabled={isProcessing}>
            Ask
          </button>
        </div>

      </div>
    </div>
  );
};

export default ChatbotV2;
